using System;
using System.IO;
using System.Windows.Media;
using System.Windows.Media.Imaging;

namespace RobloxAccountManager;

/// <summary>
/// Application icon, hard-coded as a base64 PNG so the build and runtime never depend
/// on a loose icon.png on disk (that file is git-ignored). Used for every Window.Icon
/// and the in-app brand mark. Regenerate from icon.png with the icon build step.
/// </summary>
public static class AppIcon
{
    private static readonly string[] _parts =
    {
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
        "",
    };

    private static ImageSource? _image;

    /// <summary>Frozen 256x256 app icon decoded once from the hard-coded PNG.</summary>
    public static ImageSource Image => _image ??= Load();

    private static ImageSource Load()
    {
        byte[] bytes = Convert.FromBase64String(string.Concat(_parts));
        var bmp = new BitmapImage();
        bmp.BeginInit();
        bmp.CacheOption = BitmapCacheOption.OnLoad;
        bmp.StreamSource = new MemoryStream(bytes);
        bmp.EndInit();
        bmp.Freeze();
        return bmp;
    }
}
